  ('elementary-7fec267e-moex-00586', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '以下何種權利屬於智慧財產權？', '["債權", "抵押權", "商標權", "姓名權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00587', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '甲基金會自創辦以來，致力於雛妓救援與家暴受害者庇護，近年尤努力消彌社會中所有性/性別暴力行為 與壓迫，以建立性別公義的社會。有關甲基金會的敘述，下列何者正確？', '["和政黨一樣都是屬於非營利組織", "從民法的屬性分類屬於社團法人", "關心社會議題的層面較政黨多元", "常藉由政治參選達成該組織宗旨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00588', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '柔柔生長在一個小康的家庭，父母親從小就栽培她學習各項才藝，塑造了柔柔高雅的氣質和談吐。上述 現象最適合用下列那一種概念加以說明？', '["經濟資本", "社會資本", "象徵資本", "文化資本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00589', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '據環保團體估計，每年約有一千多萬噸的塑膠垃圾流入海中，超過 700 種海洋物種受到海洋塑膠污染的 影響，海洋垃圾也造成對船舶航行的阻礙、生態系惡化等不良影響，前述現象最適合用下列何種概念 說明？', '["外部成本內部化", "共有財的悲歌", "搭便車心態", "鄰避效應"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00590', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '某甲認為年輕人自己不夠努力因此才買不起房子，某乙反駁認為，許多財團手握大筆資金投入房地產市 場，成為炒房元兇，年輕人靠著微薄的薪水，不論如何努力也永遠追不上高漲的房價。某乙的說法最接 近下列何項觀點？', '["功能論", "衝突論", "成就地位論", "人力資本論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00591', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '美國大選常見各族群文化與價值之間的激辯，但似乎都不影響美國民眾對國家的支持。請問美國人民對 國家的齊心支持，最可能基於下列何項理由？', '["公民身分的保障形成對國家的認同", "國家透過嚴密監控形成公民意識", "透過種族通婚大幅減少社會分歧", "所得平均形成強大的社會凝聚力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00592', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '隨著永續發展思潮的風起雲湧，消費者願意以合理價格，購買以友善耕作方式所生產的蔬果，此種購買 行為符合下列何種概念？', '["綠色廠房", "企業社會責任", "比較利益", "綠色消費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00593', 'elementary-7fec267e', 'elementary-7fec267e-moex-111-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '阮氏是從東南亞來臺灣從事家庭看護的移工，工作已經一年多，非常細心負責，深受被照顧者李伯伯家 人的喜愛，彼此感情非常好。某日她推著坐在輪椅上的李伯伯要去投票，遭到一輛闖紅燈的機車撞上， 讓她腿部扭傷，醫生評估必須休養兩週。關於阮氏在臺灣享有的權利，下列何者正確？', '["阮氏在臺灣居住已超過四個月，故具有市長投票權", "因阮氏是外國人，故無法獲得肇事者的醫療賠償費", "阮氏在休養期間享有國民年金保險給付的權利", "在臺灣工作期間，雇主可以為阮氏投保勞工保險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:01+00:00", "source_pdf_sha1": "63d872a63c05", "answer_pdf_sha1": "043f51fbe050", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
